# Reading Body Track CHOP output
# Channels follow pattern: person0:joint_name:axis

def get_skeleton_joints(bodyTrackChop, person_index=0):
    """
    Extract all joint positions for a specific person.
    Returns dict of {joint_name: (x, y, z)}
    """
    joints = {}
    prefix = f'person{person_index}:'

    for chan in bodyTrackChop.chans():
        if chan.name.startswith(prefix):
            parts = chan.name[len(prefix):].split(':')
            if len(parts) == 2:
                joint, axis = parts
                if joint not in joints:
                    joints[joint] = [0, 0, 0]
                axis_idx = {'x': 0, 'y': 1, 'z': 2}.get(axis, 0)
                joints[joint][axis_idx] = chan[0]

    return {k: tuple(v) for k, v in joints.items()}

# Example: check if person is raising both hands
def detect_hands_raised(bodyTrackChop, person_index=0):
    joints = get_skeleton_joints(bodyTrackChop, person_index)
    if 'left_wrist' in joints and 'left_shoulder' in joints:
        left_raised = joints['left_wrist'][1] > joints['left_shoulder'][1]
        right_raised = joints['right_wrist'][1] > joints['right_shoulder'][1]
        return left_raised and right_raised
    return False
